// Parse Fathom notification email
// Fathom emails typically contain:
// - Meeting title in the subject
// - AI-generated summary with highlights
// - Action items
// - Recording link
// - Attendee list

const items = $input.all();
const results = [];

for (const item of items) {
  const email = item.json;
  const subject = email.subject || 'Untitled Meeting';
  const rawDate = email.date || email.internalDate || new Date().toISOString();
  const body = email.textPlainBody || email.textPlain || email.snippet || '';
  const htmlBody = email.textHtml || email.body || '';

  // Extract meeting title - Fathom subjects often look like:
  // "Your call recording: Meeting Title" or "Meeting Title - Call Summary"
  let title = subject
    .replace(/^(Your call recording:\s*|Call summary:\s*|Fathom:\s*)/i, '')
    .replace(/\s*-\s*(Call Summary|Recording Ready)$/i, '')
    .trim() || subject;

  // Format date nicely
  let date;
  try {
    const d = new Date(rawDate);
    date = d.toISOString().split('T')[0];
  } catch (e) {
    date = new Date().toISOString().split('T')[0];
  }

  // Extract Fathom recording link
  let fathomLink = '';
  const linkPatterns = [
    /https?:\/\/[^\s"'<>]*fathom\.video[^\s"'<>]*/gi,
    /https?:\/\/[^\s"'<>]*app\.fathom\.video[^\s"'<>]*/gi
  ];
  for (const pattern of linkPatterns) {
    const matches = (body + ' ' + htmlBody).match(pattern);
    if (matches && matches.length > 0) {
      fathomLink = matches[0].replace(/[)\]}>]+$/, '');
      break;
    }
  }

  // Extract attendees from email body
  // Fathom emails often list participants
  let attendees = '';
  const attendeePatterns = [
    /(?:Participants|Attendees|With):\s*([^\n]+)/i,
    /(?:Call with|Meeting with)\s+([^\n.]+)/i
  ];
  for (const pattern of attendeePatterns) {
    const match = body.match(pattern);
    if (match) {
      attendees = match[1].trim();
      break;
    }
  }
  // Also check CC/To headers as fallback
  if (!attendees) {
    const to = email.to?.text || email.to || '';
    const cc = email.cc?.text || email.cc || '';
    attendees = [to, cc].filter(Boolean).join(', ');
  }

  // Extract AI summary from Fathom email body
  // Fathom structures emails with sections like Summary, Highlights, Action Items
  let summary = '';
  let actionItems = '';

  // Try to parse summary section
  const summaryPatterns = [
    /(?:Summary|Overview|Key Points)[:\s]*\n([\s\S]*?)(?=\n(?:Action Items|Highlights|Key Decisions|Next Steps|---)|$)/i,
    /(?:Here'?s? (?:a |your )?(?:summary|recap))[:\s]*\n([\s\S]*?)(?=\n(?:Action Items|Highlights|---)|$)/i
  ];
  for (const pattern of summaryPatterns) {
    const match = body.match(pattern);
    if (match) {
      summary = match[1].trim().substring(0, 2000);
      break;
    }
  }
  // Fallback: use first meaningful chunk of body as summary
  if (!summary) {
    const lines = body.split('\n').filter(l => l.trim().length > 20);
    summary = lines.slice(0, 10).join('\n').substring(0, 2000) || body.substring(0, 2000);
  }

  // Try to parse action items section
  const actionPatterns = [
    /(?:Action Items|Next Steps|To[- ]?Do|Follow[- ]?ups?)[:\s]*\n([\s\S]*?)(?=\n(?:Summary|Highlights|Key Decisions|---)|$)/i,
    /(?:Action Items|Next Steps)[:\s]*\n([\s\S]*?)$/i
  ];
  for (const pattern of actionPatterns) {
    const match = body.match(pattern);
    if (match) {
      actionItems = match[1].trim().substring(0, 1500);
      break;
    }
  }

  results.push({
    json: {
      title,
      date,
      body: body.substring(0, 3000),
      summary,
      action_items: actionItems || 'None identified',
      fathom_link: fathomLink,
      attendees,
      email_id: email.id || email.messageId || ''
    }
  });
}

return results;

